/**
 * Generates report with explicit database error handling.
 *
 * @reportId Report identifier.
 * @return struct
 * @throws application When report data cannot be loaded.
 */
public struct function generateReport(required numeric reportId) {
  try {
    return variables.reportService.build(arguments.reportId);
  } catch (database dbEx) {
    variables.logger.error('Database failure while generating report', dbEx);
    throw(type = 'application', message = 'Unable to generate report right now.', detail = dbEx.message);
  }
}

/**
 * Maps exception to user-safe FW/1 response payload.
 *
 * @exception Caught exception structure.
 * @return struct
 */
public struct function toUserSafeError(required struct exception) {
  variables.logger.error('Unhandled request exception', arguments.exception);
  return {
    message: 'An unexpected error occurred. Please contact support if this continues.',
    code: 'GENERIC_FAILURE'
  };
}

/**
 * Loads account detail with explicit failure contract.
 *
 * @accountId Account identifier.
 * @return struct
 * @throws application When account is not found.
 */
public struct function getAccountOrFail(required numeric accountId) {
  var account = variables.accountRepository.findById(arguments.accountId);
  if (!structKeyExists(account, 'id')) {
    throw(type = 'application', message = 'Account not found.');
  }
  return account;
}

/**
 * Persists profile update with specific exception handling.
 *
 * @profile Struct of profile fields.
 * @return void
 * @throws application When persistence fails.
 */
public void function saveProfile(required struct profile) {
  try {
    variables.profileRepository.save(arguments.profile);
  } catch (database dbEx) {
    throw(type = 'application', message = 'Profile save failed.', detail = dbEx.message);
  }
}

/**
 * Executes operation with bounded retry and typed failure semantics.
 *
 * @operationName Friendly operation label.
 * @executor Callback to run.
 * @return any
 * @throws application When retries are exhausted.
 */
public any function withRetry(required string operationName, required any executor) {
  var attempts = 0;
  while (attempts < 3) {
    attempts++;
    try {
      return arguments.executor();
    } catch (database dbEx) {
      if (attempts == 3) {
        throw(type = 'application', message = arguments.operationName & ' failed after retries.', detail = dbEx.message);
      }
    }
  }
  throw(type = 'application', message = arguments.operationName & ' failed unexpectedly.');
}

/**
 * Sends a notification and returns a user-safe result on failure.
 *
 * @userId numeric   Recipient user identifier.
 * @return struct
 */
public struct function sendNotification(required numeric userId) {
  try {
    variables.notificationGateway.send(arguments.userId);
    return { success: true };
  } catch (any ex) {
    variables.logger.error('Notification send failure for userId=' & arguments.userId, ex.message);
    return { success: false, error: 'Notification could not be delivered. Please try again.' };
  }
}

