/**
 * Calls an external API with a limited retry strategy.
 *
 * @payload struct   Request payload.
 * @return struct
 * @throws application After maxAttempts failures.
 */
public struct function callWithRetry(required struct payload) {
  var maxAttempts = 3;
  var lastEx = {};

  for (var attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return variables.apiGateway.call(arguments.payload);
    } catch (any ex) {
      lastEx = ex;
      if (attempt < maxAttempts) {
        sleep(200 * attempt);
      }
    }
  }

  throw(type='application', message='External API unavailable after ' & maxAttempts & ' attempts.', detail=lastEx.message);
}

wrong:
// Wrong: single attempt with no retry — transient failures cause immediate user-visible errors
public struct function callWithRetry(required struct payload) {
  return variables.apiGateway.call(arguments.payload);
}

