/**
 * Handles uncaught exceptions in the users controller.
 *
 * @exception struct   FW/1 exception structure.
 * @event string       FW/1 event name.
 * @rc struct          Request collection.
 * @prc struct         Private request collection.
 * @return void
 */
public void function onError(
  required struct exception,
  required string event,
  required struct rc,
  required struct prc
) {
  variables.logger.error('Controller error in event=' & arguments.event, arguments.exception.message);
  arguments.prc.errorMessage = 'An unexpected error occurred. Our team has been notified.';
  variables.fw.redirect('main.index');
}

/**
 * Reads a file resource and releases the handle in finally.
 *
 * @filePath string   Absolute path to the file.
 * @return string
 * @throws application When the file cannot be read.
 */
public string function readFile(required string filePath) {
  var content = '';
  var fileObj = fileOpen(arguments.filePath, 'read');

  try {
    content = fileReadLine(fileObj);
  } catch (any ex) {
    throw(type='application', message='Cannot read file.', detail=ex.message);
  } finally {
    fileClose(fileObj);
  }

  return content;
}

